mapper.select:
SELECT id, interface_id, config_name, url, http_method, timeout_ms, auth_type, auth_value, api_key_header, token_url, client_id, client_secret, token_scope, content_type, request_headers, request_template, success_http_codes, response_path, ssl_verify, proxy_host, proxy_port, proxy_user, proxy_password, is_active, created_at, updated_at FROM eai_rest_config
AND interface_id = #{interfaceId}
ORDER BY id
